scwin.onpageload = async function() {
    scwin.parent = $p.parent();

    // 작업단계 selectbox
    $c.sbm.execute(sbm_co_ds_combo2);

    // 노무원/용역직
    ds_main5.setRowPosition(0);
};

/**
 * UDC 완료. 그리는 시점 차이 보완. 
 */
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        $c.gus.cfEnableObj(acb_wrkIndictNo, false);
	    $c.gus.cfEnableObj(btn_no1,false);
    }, {"delay":50});

};

/**
 * 조회
 */
scwin.f_Retrieve = function (){
    ds_search.set("wrkIndictNo", scwin.parent.txtWrkIndictNo.getValue());
    // ds_search.UserStatus(1) = 1;
    $c.sbm.execute(sbm_retrieve);
};

/**
 * [Shift 계획 불러오기] 버튼 클릭
 * (부모창 [Shift 계획 불러오기] 클릭 시 호출)
 */
scwin.f_search = async function () {

	if (ds_hidden.get("txt_wrkIndictNo") == "") {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["작업지시번호","작업지시번호 생성"]); //"@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
		return;
	}
  	ds_search.set("wrkIndictNo", acb_wrkIndictNo.getValue());

    $c.sbm.execute(sbm_search);

};

/**
 * 하역직 Grid 행추가 버튼 클릭
 */
scwin.f_AddRow = async function () {
	if (ds_hidden.get("txt_wrkIndictNo") == "") {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["작업지시번호","작업지시번호 생성"]); //"@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
		return;
	}
    var rowIndex = ds_main4.insertRow();
    // ds_main4.setRowPosition(rowIndex);
    ds_main4.setCellData(rowIndex, "wrkIndictNo", ds_hidden.get("txt_wrkIndictNo"));

    gr_main4.setCellReadOnly(rowIndex, "staffNo", false);
    gr_main4.setCellReadOnly(rowIndex, "staffNm", false);

    gr_main4.setFocusedCell(rowIndex, "staffNo", true);

};

/**
 * 하역직 Grid 행삭제 버튼 클릭
 */
scwin.f_deleteRow = function () {
	if (ds_main4.getCellData(0, "tableFlag") == 306) {
		if (ds_main4.getRowCount() == 1) {
			ds_main4.removeAll();
            ds_main4.reform();
		} else {
            // export ??
			// var dataset = ds_main4.ExportData(2, ds_main4.getRowCount(),true);
			// ds_main4.removeAll();
			// ds_main4.ImportData(dataset);

            const dataset = ds_main4.getAllJSON().slice(1);
            ds_main4.removeAll();
            ds_main4.reform();
            ds_main4.setJSON(dataset);
            ds_main4.reform();
		}
	} else {
		// ds_main4.DeleteMarked();

        // var delArr = ds_main4.getDeletedIndex();
        // for (var i = ds_main4.getRowCount() - 1 ; i >= 0 ; i--){
        //     for(var j = 0 ; j < delArr.lenth ; j++){
        //         if (i == j){
        //             ds_main4.deleteRow(i);
        //         }
        //     }
        // }

        let row = gr_main4.getFocusedRowIndex(); 
        if(row > -1) {
            $c.data.deleteRow(gr_main4);
        }
	}
};

/**
 * 하역직 Grid 사번조회 팝업
 */
scwin.f_openCommCdPopUp = async function (argFlg) {

    // 선언부
    var rtnList = new Array();	
    var pCode = "";
    var pName = "";
    var arrParam = new Array();

    const rowPosition = ds_main4.getRowPosition();

    // 조회 조건 담기
    if (argFlg == 1) {
        pCode = ds_main4.getCellData(rowPosition,"staffNo");
        ds_main4.setCellData(rowPosition, "staffNm", "");
    } else {
        pName = ds_main4.getCellData(rowPosition, "staffNm");
        ds_main4.setCellData(rowPosition, "staffNo", "");
    }

    arrParam[0] = pCode; //사번
    arrParam[1] = pName; //사원명
    arrParam[2] = scwin.parent.txt_hlobranCd.getValue(); //점소코드
    arrParam[3] = scwin.parent.txt_hlobranNm.getValue();  //점소명
    arrParam[4] = ''; //작업장코드
    arrParam[5] = '01';//직종  (정규직)
    arrParam[6] = '02,D' //상세직종코드 (하역직)
    arrParam[7] = ''; //직급
    arrParam[8] = scwin.parent.ica_wrkDt.getValue();  //작업예정일자
    arrParam[9] = 'Y'; //배치가능여부
    arrParam[10] = 'T';
    arrParam[11] = '1'; //직종
    arrParam[12] = scwin.parent.acb_shiftClsCd.getValue(); //Shift 구분코드

    // rtnList = window.showModalDialog("/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.jsp", arrParam, "dialogHeight:450px; dialogWidth:530px; resizable=no; help:no; status:no; center=true; "); 	
    let win_url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml";
    let opts = {
        id : "searchEmpNoPop"
        , popupName : "사번조회"
        , modal : true
        , type : "browserPopup"
        , width : 840
        , height : 400
        , title : "사번조회"
    };

    var rtnList = await $c.win.openPopup(win_url, opts, arrParam);
    if (rtnList != null && rtnList[1] != undefined) {

        const mJson = ds_main4.getMatchedJSON("staffNo", rtnList[2], true);
        if (mJson.length > 0) {
            await $c.gus.cfAlertMsg("중복하여 입력할 수 없습니다.");
            return;
        }

        ds_main4.setCellData(rowPosition, "staffNo", rtnList[2]);	// 사번
        ds_main4.setCellData(rowPosition, "staffNm", rtnList[3]);	// 이름
        ds_main4.setCellData(rowPosition, "occpgrdCd", rtnList[4]);	// 직급코드
        ds_main4.setCellData(rowPosition, "occpgrdNm", rtnList[5]);	// 직급명
        ds_main4.setCellData(rowPosition, "occptypeCd", rtnList[8]);	// 직종코드
        ds_main4.setCellData(rowPosition, "occptypeNm", rtnList[9]);	// 직종명

        //(0)직종코드		
        //(1)직종명	        
        //(2)인원번호		
        //(3)인원명	                          
        //(4)직급		    
        //(5)직급명		    
        //(6)물류점소코드   
        //(7)물류점소명		
        //(8)상세직종코드	
        //(9)상세직종명		                  
        //(10)배치가능여부	
        //(11)본사계약직여부 
        //(12)연근여부		

    } else {
        ds_main4.setCellData(rowPosition, "staffNo", "");	// 사번
        ds_main4.setCellData(rowPosition, "staffNm", "");	// 이름
        ds_main4.setCellData(rowPosition, "occpgrdCd", "");	// 직급코드
        ds_main4.setCellData(rowPosition, "occpgrdNm", "");	// 직급명
        ds_main4.setCellData(rowPosition, "occptypeCd", "");	// 직종코드
        ds_main4.setCellData(rowPosition, "occptypeNm", "");	// 직종명
    }
};

/**
 * 부모창(op_204_02_03b.xml)에서 호출
 */
scwin.f_RetrievePierCdCall = function () {
    scwin.f_RetrievePierCd(scwin.parent.txt_hcvsslMgntNo.getValue(), scwin.parent.ds_main2.getCellData(0, "wrkIndictNo"));
};

/**
 * 부두 조회(점소 선택시 해당 점소의 부두만 조회)
 */
scwin.f_RetrievePierCd = function (param1, param2) {

    co_ds_combo1_search.set("sysCd", "DailyStevedoringWorkIndicationEBC");
    co_ds_combo1_search.set("queryId", "retrieveWorkPlanListCombo");
    co_ds_combo1_search.set("param1", param1);
    co_ds_combo1_search.set("param2", param2);

    $c.sbm.execute(sbm_co_ds_combo1);
};

scwin.sbm_co_ds_combo1_submit = function (e) {

};

scwin.sbm_co_ds_combo1_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        co_ds_combo1.setJSON(e.responseJSON.GAUCE);

        if (co_ds_combo1.getRowCount() > 0) {
            $c.gus.cfEnableObj(acb_wrkIndictNo ,true);
            $c.gus.cfEnableObj(btn_no1, true);
        } else {
            $c.gus.cfEnableObj(acb_wrkIndictNo, false);
            $c.gus.cfEnableObj(btn_no1, false);
        }
        if (scwin.parent.ds_main2.getRowCount() > 0) {
            if (scwin.parent.ds_main2.getCellData(0, "completeProcYn") == 1) {
                $c.gus.cfEnableObj(btn_no1, false);
            } else {
                $c.gus.cfEnableObj(btn_no1, true);
            }
        }

        ds_main4.reform();
    };

};

scwin.sbm_co_ds_combo1_submiterror = function (e) {

};

/**
 * [Shift 계획 불러오기] 클릭
 */
scwin.btn_no1_onclick = function (e) {
    $c.sbm.execute(sbm_search);
};

/**
 * [저장] 클릭
 */
scwin.btn_save_onclick = function (e) {
    scwin.f_main4Save();
};

/**
 * 저장
 */
scwin.f_main4Save = async function (){
    if ((!ds_main4.getModifiedIndex().length > 0) && (!ds_main5.getModifiedIndex().length > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["인원투입계획"]); // "@은(는) 변경된 사항이 없습니다."
        return;
    }

    const validArry = [
        {id:"staffNo", name: "사번", mandatory: true, key: true},
        {id:"staffNm", name: "이름", mandatory: true, key: true},
        {id:"wrkStpCd", name: "작업단계", mandatory: true}
    ];
    let gridName = "하역직";
    if(!await $c.gus.cfValidateGrid(gr_main4, null, null, validArry, gridName)){
         return false;
    }

    let count = 0;
    for(let i = 0; i < ds_main4.getRowCount() ; i++) {
        if (ds_main4.getCellData(i, "cfmanYn") == 1) {
            count++;
        }   	
    }
    if (count < 1) {
        await $c.gus.cfAlertMsg("Chief 포맨을 선택하여 주십시오.");
        return;
    }
    for(let i = 0; i < ds_main4.getRowCount() ; i++) {  

        const rowInfo = ds_main4.getRowJSON(i);
        if (rowInfo.rowStatus == "C" || rowInfo.rowStatus == "U") {
            ds_ecsYn.removeAll();
            ds_main4.reform();
            ds_condition.set("staffNo", rowInfo.staffNo);
            ds_condition.set("wrkDt", scwin.parent.ica_wrkDt.getValue()); 

            // 연근 조회
            var rs = await $c.sbm.execute(sbm_retrieveEcsYn);
            if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {

                const {ecsYn} = ds_ecsYn.getRowJSON(0);
                if (ecsYn == 1) {
                    if (await $c.win.confirm(rowInfo.staffNm + "의 인원투입계획은 연근입니다.</br> 그래도 저장하시겠습니까?")) {
                    } else {
                        return false;	   		
                    }    		    	
                } else if (ecsYn == 2) {
                    if (await $c.win.confirm(rowInfo.staffNm + "의 인원투입계획은 연연근입니다.</br> 그래도 저장하시겠습니까?")) {
                    } else {    		
                        return false;
                    }
                }
            };
        }   	
    }
    $c.sbm.execute(sbm_main4);
};

/**
 * [저장] 선처리
 */
scwin.sbm_main4_submit = function (e) {

};

/**
 * [저장] 후처리
 */
scwin.sbm_main4_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();
};

scwin.sbm_main4_submiterror = function (e) {

};

/**
 * 저장 후 재조회 전처리
 */
scwin.sbm_retrieve_submit = function (e) {

};

/**
 * 저장 후 재조회 후처리
 */
scwin.sbm_retrieve_submitdone = function (e) {

    // 노무원/용역직
    ds_main5.setRowPosition(0);

    txt_totalRows.setValue(ds_main4.getTotalRow());
};

scwin.sbm_retrieve_submiterror = function (e) {

};

/**
 * [Shift 계획 불러오기] 전처리
 */
scwin.sbm_search_submit = function (e) {
    ds_search.set("wrkIndictNo", acb_wrkIndictNo.getValue());
};

/**
 * [Shift 계획 불러오기] 후처리
 */
scwin.sbm_search_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {

        if (ds_main4.getCellData(0, "tableFlag") == 306) {
            ds_main4.setCellData(0, "wrkStpCd", '004');
        }

        for(let i = 0 ; i < ds_main4.getRowCount(); i++) {
            ds_hidden.set("txt_wrkIndictNo", scwin.parent.txtWrkIndictNo.getValue());
            ds_main4.setCellData(i, "wrkIndictNo", ds_hidden.get("txt_wrkIndictNo"));
        }

        for(let i = 0 ; i < ds_main5.getRowCount(); i++) {
            ds_hidden.set("txt_wrkIndictNo", scwin.parent.txtWrkIndictNo.getValue());
            ds_main5.setCellData(i, "wrkIndictNo", ds_hidden.get("txt_wrkIndictNo"));
        }
    }

    scwin.ds_main4_onloadcomplete();

};

scwin.sbm_search_submiterror = function (e) {

};

/**
 * tableFlag==306이면 로드 직후
    ① 1행 wrkStpCd를 '004'로 강제 설정하고
    ② completeProcYn==0일 때만 데이터를 유지, 아니면 ds_main4를 통째로 비운다.
 */
scwin.ds_main4_onloadcomplete = function() {
    if (ds_main4.getCellData(0, "tableFlag") == 306) {
		ds_main4.setCellData(0, "wrkStpCd", '004');
        // export ??
		// var dataset = ds_main4.ExportData(1,ds_main4.getRowCount(),true);
		// ds_main4.ClearData();
		// if (scwin.parent.ds_main2.NameValue(1,"completeProcYn") == 0) {
		// 	ds_main4.ImportData(dataset);
		// }

        const dataset = ds_main4.getAllJSON().slice(1);
        ds_main4.removeAll();
        ds_main4.reform();
        if (scwin.parent.ds_main2.getCellData(0, "completeProcYn") == 0) {
            ds_main4.setJSON(dataset);
            ds_main4.reform();
        }
	}

    for(let i=0; i<ds_main4.getTotalRow(); i++) {
        gr_main4.setCellReadOnly(i, "staffNo", true);
        gr_main4.setCellReadOnly(i, "staffNm", true);
    }

    // 노무원/용역직
    ds_main5.setRowPosition(0);
};

/**
 * 그리드 textImage click
 */
scwin.gr_main4_ontextimageclick = function (rowIndex, columnIndex) {
    var colid = gr_main4.getColumnID(columnIndex);
    if (colid == "staffNo") {
		scwin.f_openCommCdPopUp(1);
	} else if (colid == "staffNm") {
		scwin.f_openCommCdPopUp(2);
	}
};

/**
 * 그리드 edit end
 */
scwin.gr_main4_oneditend = function (row, columnIndex, value) {

    const colid = gr_main4.getColumnID(columnIndex);

    if (colid == "staffNo" && ds_main4.getCellData(row, colid) != "") {
		scwin.oldData_staffNo = ds_main4.getCellData(row,colid);
	} else if (colid == "staffNm" && ds_main4.getCellData(row,colid) != "") {
		scwin.oldData_staffNm = ds_main4.getCellData(row,colid);
	}
};

/**
 * 그리드 after edit
 */
scwin.gr_main4_onafteredit = function (row, columnIndex, value) {
    const colid = gr_main4.getColumnID(columnIndex);
    const inputValue = ds_main4.getCellData(row, colid);

    if (inputValue != scwin.oldData_staffNo && inputValue != "") {

        if (colid === "staffNo") {
            scwin.f_openCommCdPopUp(1);
        } else if (colid === "staffNm") {
            scwin.f_openCommCdPopUp(2);
        }
    } else {
        ds_main4.setCellData(row, "staffNo", "");	// 사번
        ds_main4.setCellData(row, "staffNm", "");	// 이름
        ds_main4.setCellData(row, "occpgrdCd", "");	// 직급코드
        ds_main4.setCellData(row, "occpgrdNm", "");	// 직급명
        ds_main4.setCellData(row, "occptypeCd", "");	// 직종코드
        ds_main4.setCellData(row, "occptypeNm", "");	// 직종명
    }
};

/**
 * 그리드 row index change
 */
scwin.gr_main4_onrowindexchange = function (rowIndex, oldRow) {
    scwin.f_defaultCall(rowIndex);	// Key 값 수정 X
};

/**
 * Key 값 수정 X
 */
scwin.f_defaultCall = function(rowIndex) {
//	if(gr_main4.GetColumn() == "staffNo"){

    if (rowIndex) {
        if ("C" == ds_main4.getRowStatus(rowIndex)){
            gr_main4.setCellReadOnly(rowIndex, "staffNo", false);
            gr_main4.setCellReadOnly(rowIndex, "staffNm", false);
        } else {
            gr_main4.setCellReadOnly(rowIndex, "staffNo", true);
            gr_main4.setCellReadOnly(rowIndex, "staffNm", true);
        }
    } else {
        gr_main4.setColumnReadOnly("staffNo", true);
        gr_main4.setColumnReadOnly("staffNm", true);
    }

//	}
};

/**
 * 그리드 cell click
 */
scwin.gr_main4_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if (columnId == "cfmanYn" && ds_main4.getCellData(rowIndex, columnId) == "1") {
        const cfmanYn = ds_main4.getColSum("cfmanYn");
        if (cfmanYn > 1) {
            await $c.gus.cfAlertMsg("Chief 포맨은 두명이상 선택할 수 없습니다.");
            ds_main4.setCellData(rowIndex, "cfmanYn", "");
            return;
        }
	}
};

/**
 * 작업계획 조회 선처리
 */
scwin.sbm_co_ds_combo2_submit = function (e) {
    const condition = {
        upperWrkStpCd: "01",
        lvl: "3",
        wrkPlanTrgtYn: "1"
    }
    ds_wrkStpCd.setJSON(condition);
};

/**
 * 작업계획 조회 후처리
 */
scwin.sbm_co_ds_combo2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        ds_wrkStpCdRslt.setJSON(e.responseJSON.GAUCE);
    };
};

/**
 * 작업계획 조회 후처리(에러)
 */
scwin.sbm_co_ds_combo2_submiterror = function (e) {
    // Response Status 코드가 오류 (200 미만 300 이상) 일 경우 동작
};
